//! Config from env: migrate_from URL, migrate_to_store URL, credentials.
//! Table list is read from the file generated by order-tables (migrate_tables_order.rs).

use std::env;
use std::path::Path;

pub struct Config {
    pub migrate_from_database_url: String,
    pub migrate_to_store_url: String,
    pub store_account_id: String,
    pub store_account_secret: String,
    pub store_root_account_id: Option<String>,
    pub store_root_account_secret: Option<String>,
    pub tables: Vec<String>,
    pub app_id: String,
    pub error_log_path: String,
}

impl Config {
    pub fn from_env() -> Result<Self, Box<dyn std::error::Error + Send + Sync>> {
        let migrate_from_database_url = env::var("MIGRATE_FROM_DATABASE_URL")
            .map_err(|_| "MIGRATE_FROM_DATABASE_URL is required")?;
        let migrate_to_store_url =
            env::var("MIGRATE_TO_STORE_URL").map_err(|_| "MIGRATE_TO_STORE_URL is required")?;
        let store_account_id = env::var("MIGRATE_STORE_ACCOUNT_ID")
            .map_err(|_| "MIGRATE_STORE_ACCOUNT_ID is required")?;
        let store_account_secret = env::var("MIGRATE_STORE_ACCOUNT_SECRET")
            .map_err(|_| "MIGRATE_STORE_ACCOUNT_SECRET is required")?;
        let store_root_account_id = env::var("MIGRATE_STORE_ROOT_ACCOUNT_ID").ok();
        let store_root_account_secret = env::var("MIGRATE_STORE_ROOT_ACCOUNT_SECRET").ok();
        let tables_file = env::var("MIGRATE_TABLES_FILE")
            .unwrap_or_else(|_| "migrate_tables_order.rs".to_string());
        let tables = load_tables_from_order_file(&tables_file)?;
        let app_id = env::var("MIGRATE_APP_ID").unwrap_or_else(|_| "portal".to_string());
        let error_log_path =
            env::var("MIGRATE_ERROR_LOG").unwrap_or_else(|_| "migrate_errors.log".to_string());

        Ok(Self {
            migrate_from_database_url,
            migrate_to_store_url: migrate_to_store_url.trim_end_matches('/').to_string(),
            store_account_id,
            store_account_secret,
            store_root_account_id,
            store_root_account_secret,
            tables,
            app_id,
            error_log_path,
        })
    }

    /// Connect to the source (migrate_from) database. Session is set to read-only so
    /// no INSERT/UPDATE/DELETE can run against the source (safe for QA).
    pub async fn connect_postgres(
        &self,
    ) -> Result<tokio_postgres::Client, Box<dyn std::error::Error + Send + Sync>> {
        let url = ensure_sslmode_disable(&self.migrate_from_database_url);
        let (client, connection) = tokio_postgres::connect(&url, tokio_postgres::NoTls).await?;
        tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("postgres connection error: {}", e);
            }
        });
        // Enforce read-only: only SELECT is allowed; mutations will error
        client
            .batch_execute("SET default_transaction_read_only = on")
            .await?;
        Ok(client)
    }
}

/// Load table names from the Rust array file generated by order-tables (e.g. migrate_tables_order.rs).
/// Only parses the MIGRATE_TABLES_ORDER array so we do not treat MIGRATE_CIRCULAR_FK_COLS
/// column names (e.g. "account_id", "created_by") as table names.
fn load_tables_from_order_file(
    path: &str,
) -> Result<Vec<String>, Box<dyn std::error::Error + Send + Sync>> {
    let content = std::fs::read_to_string(Path::new(path)).map_err(|e| {
        format!(
            "Failed to read table order file '{}': {}. Run 'make order-tables' first.",
            path, e
        )
    })?;

    let mut tables = Vec::new();
    let mut in_order_array = false;

    for line in content.lines() {
        let trimmed = line.trim();
        // Skip comment-only lines
        if trimmed.starts_with("//") {
            continue;
        }
        // Start collecting after we see MIGRATE_TABLES_ORDER and its opening &[
        if trimmed.contains("MIGRATE_TABLES_ORDER") && trimmed.contains("&[") {
            in_order_array = true;
            // Same line may have first table: &[ "foo",
            if let Some(s) = extract_quoted(trimmed) {
                tables.push(s);
            }
            if trimmed.contains("];") {
                break;
            }
            continue;
        }
        if in_order_array {
            if trimmed.contains("];") {
                if let Some(s) = extract_quoted(trimmed) {
                    tables.push(s);
                }
                break;
            }
            if let Some(s) = extract_quoted(trimmed) {
                tables.push(s);
            }
        }
    }

    if tables.is_empty() {
        return Err(format!(
            "No tables found in MIGRATE_TABLES_ORDER in '{}'. Run 'make order-tables' to generate it.",
            path
        )
        .into());
    }
    Ok(tables)
}

/// Extract the first quoted string from a line (e.g. "organizations", or // "commented" -> None for comment lines).
fn extract_quoted(line: &str) -> Option<String> {
    let open = line.find('"')?;
    let after_open = &line[open + 1..];
    let close = after_open.find('"')?;
    Some(after_open[..close].to_string())
}

/// Append sslmode=disable to the URL if no sslmode is set (avoids "server does not support TLS" for local Postgres).
fn ensure_sslmode_disable(url: &str) -> String {
    if url.contains("sslmode=") {
        url.to_string()
    } else {
        let sep = if url.contains('?') { "&" } else { "?" };
        format!("{}{}sslmode=disable", url, sep)
    }
}
